import math

def discrete_log_bsgs(g: int, h: int, p: int) -> int | None:
    if p <= 1:
        raise ValueError("Modulus p must be greater than 1.")
    if h == 1:
        return 0

    if g == 0:
        if h == 0:
            return 1
        else:
            return None

    if g == 1:
        if h == 1:
            return 0
        else:
            return None

    N = p - 1
    m = int(math.ceil(math.sqrt(N))) 

    baby_steps = {}
    current_g_j = 1
    for j in range(m):
        if current_g_j == h:
            return j
        baby_steps[current_g_j] = j
        current_g_j = (current_g_j * g) % p

    g_m = pow(g, m, p)

    try:
        g_inv_m = pow(g_m, -1, p)
    except ValueError:
        raise ValueError(f"Modular inverse of {g}^{m} (mod {p}) does not exist. "
                         "Ensure g is coprime to p.")

    current_giant_step_val = h
    for k in range(m):
        if current_giant_step_val in baby_steps:
            j = baby_steps[current_giant_step_val]
            x = (k * m + j) % N 
            return x
        current_giant_step_val = (current_giant_step_val * g_inv_m) % p

    return None
